	"errors"
	"strings"
)

type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Validate and whitelist orderBy parameter
	validColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}

	orderByLower := strings.ToLower(strings.TrimSpace(orderBy))
	if !validColumns[orderByLower] {
		return nil, errors.New("invalid order by column")
	}

	// Normalize and validate sortDir
	sortDir = strings.ToUpper(strings.TrimSpace(sortDir))
	if sortDir != "ASC" && sortDir != "DESC" {
		return nil, errors.New("invalid sort direction")
	}

	// Build query safely using whitelisted values
	query := "SELECT id, name, price FROM products ORDER BY " + orderByLower + " " + sortDir

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

