package main

import (
	"database/sql"
	"errors"
	"strings"
)

type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Whitelist of allowed columns for sorting
	allowedColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}

	// Normalize and validate orderBy
	orderBy = strings.ToLower(strings.TrimSpace(orderBy))
	if !allowedColumns[orderBy] {
		return nil, errors.New("invalid orderBy column")
	}

	// Normalize and validate sortDir
	sortDir = strings.ToUpper(strings.TrimSpace(sortDir))
	if sortDir != "ASC" && sortDir != "DESC" {
		return nil, errors.New("invalid sort direction")
	}

	// Safe query construction using whitelisted values
	query := "SELECT id, name, price FROM products ORDER BY " + orderBy + " " + sortDir

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

